func selectedPages(paths ...string) []model.PageContract {
	wanted := map[string]bool{}
	for _, p := range paths {
		wanted[p] = true
	}
	var out []model.PageContract
	for _, p := range applicationSupplementalPages {
		if wanted[p.Path] {
			out = append(out, p)
		}
	}
	return out
}

func SupplementalPages(profileID string) []model.PageContract {
	switch profileID {
	case "application", "modular-application", "generic":
		return append([]model.PageContract(nil), applicationSupplementalPages...)
	case "reusable":
		return selectedPages(
			"configuration/runtime-configuration.md", "integrations/service-to-service.md", "integrations/external-services.md", "integrations/cloud-services.md", "integrations/dependency-matrix.md", "interfaces/endpoint-catalog.md", "messaging/event-catalog.md", "processing/job-catalog.md", "runtime/traffic-flows.md", "runtime/request-flows.md", "security/authentication.md", "security/authorization.md", "runtime/concurrency.md", "runtime/asynchronous-processing.md", "runtime/context-propagation.md", "data/database-structure.md", "data/database-programmability.md", "security/cryptography.md", "files/file-handling-and-formats.md",
		)
	case "infrastructure":
		return selectedPages(
			"configuration/runtime-configuration.md", "integrations/service-to-service.md", "integrations/external-services.md", "integrations/cloud-services.md", "integrations/dependency-matrix.md", "interfaces/endpoint-catalog.md", "messaging/event-catalog.md", "processing/job-catalog.md", "runtime/traffic-flows.md", "runtime/request-flows.md", "security/authentication.md", "security/authorization.md", "runtime/context-propagation.md", "security/cryptography.md", "files/file-handling-and-formats.md",
		)
	case "configuration":
		return selectedPages(
			"configuration/runtime-configuration.md", "integrations/external-services.md", "integrations/cloud-services.md", "integrations/dependency-matrix.md", "interfaces/endpoint-catalog.md", "processing/job-catalog.md", "security/authentication.md", "security/authorization.md", "runtime/context-propagation.md", "security/cryptography.md", "files/file-handling-and-formats.md",
		)
	case "contracts":
		return selectedPages(
			"integrations/service-to-service.md", "integrations/external-services.md", "integrations/dependency-matrix.md", "interfaces/endpoint-catalog.md", "messaging/event-catalog.md", "business/business-data.md", "security/authentication.md", "security/authorization.md", "security/cryptography.md", "files/file-handling-and-formats.md",
		)
	default:
		return nil
	}
}

