func supplementalContractsText(pages []model.PageContract) string {
	var b strings.Builder
	for _, p := range pages {
		fmt.Fprintf(&b, "### openwiki/%s\nObjective: %s\nRequired sections:\n", p.Path, p.Objective)
		for _, h := range p.RequiredHeadings {
			fmt.Fprintf(&b, "- ## %s\n", h)
		}
		fmt.Fprintf(&b, "Diagram: %s\n", diagramContract(p.RequiredDiagram))
		if p.RequiredTableHeader != "" {
			fmt.Fprintf(&b, "Required catalog header: `%s`\n", p.RequiredTableHeader)
		}
		b.WriteString("\n")
	}
	return strings.TrimSpace(b.String())
}

func SupplementalContractsText(profileID string) string {
	return supplementalContractsText(SupplementalPages(profileID))
}

func SystemSupplementalContractsText() string {
	return supplementalContractsText(SystemSupplementalPages)
}

func pageContractMap(phases []model.Phase, supplemental []model.PageContract) map[string]model.PageContract {
	out := map[string]model.PageContract{}
	for _, p := range phases {
		if p.OutputFile == "" {
			continue
		}
		out[p.OutputFile] = model.PageContract{Path: p.OutputFile, Objective: p.Objective, RequiredHeadings: p.RequiredHeadings, RequiredDiagram: p.RequiredDiagram}
	}
	for _, p := range supplemental {
		out[p.Path] = p
	}
	return out
}

func ComponentPageContracts(profile Profile) map[string]model.PageContract {
	return pageContractMap(profile.Phases, SupplementalPages(profile.ID))
}

func SystemPageContracts() map[string]model.PageContract {
	return pageContractMap(SystemPhases, SystemSupplementalPages)
}

func sortedContractPaths(contracts map[string]model.PageContract) []string {
	paths := make([]string, 0, len(contracts))
	for path := range contracts {
		paths = append(paths, path)
	}
	sort.Strings(paths)
	return paths
}
